class RLAIFAgent:
    def generate_preference(self, prompt, response_a, response_b):
        critique_prompt = f'''
        Given these principles: {self.constitution}

        Which response is better for: "{prompt}"
        Response A: {response_a}
        Response B: {response_b}

        Choose and explain why.
        '''
        return self.critic_model.generate(critique_prompt)
